-- ============================================\n-- 插入示例数据脚本\n-- 适用于家庭常备药品智能管理系统\n-- ============================================\n\n-- 使用数据库\nUSE family_medicine_db2;\n\n-- ============================================\n-- 1. 插入示例用户\n-- ============================================\n\n-- 插入测试用户\nINSERT INTO users (id, openid, phone, password, nickname, avatar_url)\nVALUES\n(1001, 'test_openid_1001', '13800138001', NULL, '张三', NULL),\n(1002, 'test_openid_1002', '13800138002', NULL, '李四', NULL)\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 2. 插入示例家庭\n-- ============================================\n\n-- 插入测试家庭\nINSERT INTO families (id, name, creator_id, invite_code)\nVALUES\n(2001, '测试家庭', 1001, 'TEST1234')\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 3. 插入家庭成员角色\n-- ============================================\n\n-- 插入家庭成员角色\nINSERT INTO family_user_roles (id, family_id, user_id, role, relationship)\nVALUES\n(3001, 2001, 1001, 'admin', 'self'),\n(3002, 2001, 1002, 'member', 'spouse')\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 4. 插入示例家庭成员\n-- ============================================\n\n-- 插入家庭成员\nINSERT INTO family_members (id, family_id, name, relationship, age)\nVALUES\n(4001, 2001, '张三', '本人', 35),\n(4002, 2001, '李四', '配偶', 33),\n(4003, 2001, '张小明', '子女', 10),\n(4004, 2001, '张父', '父亲', 60),\n(4005, 2001, '张母', '母亲', 58)\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 5. 插入示例药品\n-- ============================================\n\n-- 插入药品\nINSERT INTO medicines (id, family_id, name, manufacturer, specification, category, stock, unit, expiry_date, dosage, status)\nVALUES\n(5001, 2001, '阿莫西林胶囊', '华北制药', '0.25g*24粒', '抗生素', 10, '盒', '2024-12-31', '每次2粒，每日3次，饭后服用', 'normal'),\n(5002, 2001, '布洛芬缓释胶囊', '中美天津史克', '0.3g*12粒', '止痛药', 5, '盒', '2024-06-30', '每次1粒，每日2次，疼痛时服用', 'normal'),\n(5003, 2001, '盐酸伐地那非片', '拜耳医药', '20mg*1片', '男科用药', 3, '盒', '2025-01-31', '每次1片，按需服用，性生活前30分钟服用', 'normal'),\n(5004, 2001, '感冒清热颗粒', '北京同仁堂', '10g*10袋', '感冒药', 15, '盒', '2024-09-30', '每次1袋，每日3次，开水冲服', 'normal'),\n(5005, 2001, '维生素C片', '华北制药', '0.1g*100片', '维生素', 20, '瓶', '2025-06-30', '每次1片，每日1次，口服', 'normal'),\n(5006, 2001, '创可贴', '云南白药', '100片/盒', '医疗器械', 50, '盒', '2026-12-31', '按需使用，外用', 'normal')\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 6. 插入示例用药计划\n-- ============================================\n\n-- 插入用药计划\nINSERT INTO plans (id, family_id, medicine_name, member_name, frequency, time_slots, status, start_date, end_date)\nVALUES\n(6001, 2001, '阿莫西林胶囊', '张三', '每日3次', '["08:00", "12:00", "18:00"]', 'active', '2023-03-01', '2023-03-07'),\n(6002, 2001, '布洛芬缓释胶囊', '李四', '每日2次', '["09:00", "21:00"]', 'active', '2023-03-01', '2023-03-03'),\n(6003, 2001, '盐酸伐地那非片', '张三', '按需服用', '[]', 'active', '2023-03-01', '2023-12-31'),\n(6004, 2001, '维生素C片', '张三', '每日1次', '["08:30"]', 'active', '2023-01-01', '2023-12-31')\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 7. 插入示例用药记录\n-- ============================================\n\n-- 插入今天的用药记录\nSET @today = CURDATE();\nSET @yesterday = DATE_SUB(@today, INTERVAL 1 DAY);\n\nINSERT INTO records (id, family_id, plan_id, medicine_name, member_name, time, date, status)\nVALUES\n-- 今天的记录\n(7001, 2001, 6001, '阿莫西林胶囊', '张三', '08:00', @today, 'completed'),\n(7002, 2001, 6001, '阿莫西林胶囊', '张三', '12:00', @today, 'completed'),\n(7003, 2001, 6001, '阿莫西林胶囊', '张三', '18:00', @today, 'pending'),\n(7004, 2001, 6002, '布洛芬缓释胶囊', '李四', '09:00', @today, 'completed'),\n(7005, 2001, 6004, '维生素C片', '张三', '08:30', @today, 'completed'),\n-- 昨天的记录\n(7006, 2001, 6001, '阿莫西林胶囊', '张三', '08:00', @yesterday, 'completed'),\n(7007, 2001, 6001, '阿莫西林胶囊', '张三', '12:00', @yesterday, 'completed'),\n(7008, 2001, 6001, '阿莫西林胶囊', '张三', '18:00', @yesterday, 'completed')\nON DUPLICATE KEY UPDATE id=id;\n\n-- ============================================\n-- 完成提示\n-- ============================================\nSELECT '示例数据插入完成！' as message;